```ts hono-open-api-starter/src/routes/assets/assets.handlers.ts
import { eq } from "drizzle-orm";
import * as HttpStatusCodes from "stoker/http-status-codes";
import * as HttpStatusPhrases from "stoker/http-status-phrases";

import type { AppRouteHandler } from "@/lib/types";

import db from "@/db";
import { assets } from "@/db/schema";
import { ZOD_ERROR_CODES, ZOD_ERROR_MESSAGES } from "@/lib/constants";

import type { CreateRoute, GetOneRoute, ListRoute, PatchRoute, RemoveRoute } from "./assets.routes";

export const list: AppRouteHandler<ListRoute> = async (c) => {
  const assets = await db.query.assets.findMany();
  return c.json(assets);
};

export const create: AppRouteHandler<CreateRoute> = async (c) => {
  const asset = c.req.valid("json");
  const [inserted] = await db.insert(assets).values(asset).returning();
  return c.json(inserted, HttpStatusCodes.OK);
};

export const getOne: AppRouteHandler<GetOneRoute> = async (c) => {
  const { id } = c.req.valid("param");
  const asset = await db.query.assets.findFirst({
    where(fields, operators) {
      return operators.eq(fields.id, id);
    },
  });

  if (!asset) {
    return c.json(
      {
        message: HttpStatusPhrases.NOT_FOUND,
      },
      HttpStatusCodes.NOT_FOUND,
    );
  }

  return c.json(asset, HttpStatusCodes.OK);
};

export const patch: AppRouteHandler<PatchRoute> = async (c) => {
  const { id } = c.req.valid("param");
  const updates = c.req.valid("json");

  if (Object.keys(updates).length === 0) {
    return c.json(
      {
        success: false,
        error: {
          issues: [
            {
              code: ZOD_ERROR_CODES.INVALID_UPDATES,
              path: [],
              message: ZOD_ERROR_MESSAGES.NO_UPDATES,
            },
          ],
          name: "ZodError",
        },
      },
      HttpStatusCodes.UNPROCESSABLE_ENTITY,
    );
  }

  const [asset] = await db.update(assets)
    .set(updates)
    .where(eq(assets.id, id))
    .returning();

  if (!asset) {
    return c.json(
      {
        message: HttpStatusPhrases.NOT_FOUND,
      },
      HttpStatusCodes.NOT_FOUND,
    );
  }

  return c.json(asset, HttpStatusCodes.OK);
};

export const remove: AppRouteHandler<RemoveRoute> = async (c) => {
  const { id } = c.req.valid("param");
  const result = await db.delete(assets)
    .where(eq(assets.id, id));

  if (result.rowsAffected === 0) {
    return c.json(
      {
        message: HttpStatusPhrases.NOT_FOUND,
      },
      HttpStatusCodes.NOT_FOUND,
    );
  }

  return c.body(null, HttpStatusCodes.NO_CONTENT);
};
```

Why is my remove handler not working? It does not pick up the id from the request params. I am using the same logic as in the getOne handler, but it does not work. I am not sure what I am doing wrong. Can you help me out?
One common cause for this behavior is that the id from the URL is still a string, while your database (and maybe your schema’s expectations) treats it as a number. In other words, the parameter isn’t getting “converted” as you might expect.

For example, if your IdParamsSchema is defined like this:

  z.object({ id: z.number() })

then URL parameters (which are always strings) will fail validation or at best be left as strings – unless you add a preprocessing step. In the getOne handler you might not notice it (or your lookup might be lenient in one case) but in your remove handler the comparison

  .where(eq(assets.id, id))

is very sensitive to type. If id is a string when assets.id is a number, the query won’t match any row.

To fix this you should update your IdParamsSchema to preprocess the id, for example:

  import { z } from "zod";

  export const IdParamsSchema = z.object({
    id: z.preprocess(arg => {
     if (typeof arg === "string") return Number(arg);
     return arg;
    }, z.number())
  });

This ensures that whenever you call c.req.valid("param") (which is correct for Hono’s zod integration) the id value will be a number, and your DELETE (and update or get) operations will match the record correctly.

So, the likely reason your remove handler “doesn’t pick up” the id is that the id isn’t being converted from its default string type to a number, causing the DELETE query to not affect any rows. Updating your schema to properly cast the id will resolve the issue.
